1	import { readFileSync } from "node:fs";
2	import { quote, claim, cap, isKnownItemType, type Item, type Damage, type Incident } from "./claim-office.js";
3	
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	
8	type Scenario = {
9	  customer: { yearsWithMHPCO: number };
10	  steps: Step[];
11	};
12	
13	type Policy = { items: Item[]; remainingCap: number };
14	type StepResult = Record<string, number>;
15	
16	type ScenarioState = {
17	  customer: { yearsWithMHPCO: number };
18	  policies: Policy[];
19	  previousContracts: number;
20	};
21	
22	const handleQuoteStep = (state: ScenarioState, step: QuoteStep): StepResult => {
23	  const premium = quote({
24	    customer: {
25	      yearsWithMHPCO: state.customer.yearsWithMHPCO,
26	      previousContracts: state.previousContracts,
27	    },
28	    items: step.items,
29	  });
30	  state.policies.push({ items: step.items, remainingCap: cap(step.items) });
31	  state.previousContracts += 1;
32	  return { premium };
33	};
34	
35	const findDamageNotInPolicy = (policy: Policy, damages: Damage[]): string | undefined => {
36	  for (const damage of damages) {
37	    if (!policy.items.some((item) => item.type === damage.itemType)) {
38	      return damage.itemType;
39	    }
40	  }
41	  return undefined;
42	};
43	
44	const findExcessDamageType = (policy: Policy, damages: Damage[]): string | undefined => {
45	  const damageCounts = new Map<string, number>();
46	  for (const damage of damages) {
47	    damageCounts.set(damage.itemType, (damageCounts.get(damage.itemType) ?? 0) + 1);
48	  }
49	  for (const [type, count] of damageCounts) {
50	    const policyCount = policy.items.filter((item) => item.type === type).length;
51	    if (count > policyCount) return type;
52	  }
53	  return undefined;
54	};
55	
56	const handleClaimStep = (state: ScenarioState, step: ClaimStep): StepResult => {
57	  const policy = state.policies[step.policy];
58	  const negativeDamage = step.incident.damages.find((damage) => damage.amount < 0);
59	  if (negativeDamage !== undefined) {
60	    process.stderr.write(`error: damage amount cannot be negative (${negativeDamage.amount})\n`);
61	    process.exit(1);
62	  }
63	  const unknownDamageType = findDamageNotInPolicy(policy, step.incident.damages);
64	  if (unknownDamageType !== undefined) {
65	    process.stderr.write(`error: damage itemType "${unknownDamageType}" not in policy\n`);
66	    process.exit(1);
67	  }
68	  const excessType = findExcessDamageType(policy, step.incident.damages);
69	  if (excessType !== undefined) {
70	    process.stderr.write(`error: more damages of type "${excessType}" than insured\n`);
71	    process.exit(1);
72	  }
73	  const result = claim({ policy, incident: step.incident });
74	  policy.remainingCap = result.remainingCap;
75	  return { payout: result.payout, remainingCap: result.remainingCap };
76	};
77	
78	const processStep = (state: ScenarioState, step: Step): StepResult =>
79	  step.op === "quote" ? handleQuoteStep(state, step) : handleClaimStep(state, step);
80	
81	const runScenario = (scenario: Scenario): StepResult[] => {
82	  const state: ScenarioState = {
83	    customer: scenario.customer,
84	    policies: [],
85	    previousContracts: 0,
86	  };
87	  return scenario.steps.map((step) => processStep(state, step));
88	};
89	
90	const findUnknownItemType = (scenario: Scenario): string | undefined => {
91	  for (const step of scenario.steps) {
92	    if (step.op !== "quote") continue;
93	    for (const item of step.items) {
94	      if (!isKnownItemType(item.type)) return item.type;
95	    }
96	  }
97	  return undefined;
98	};
99	
100	const scenario: Scenario = JSON.parse(readFileSync(0, "utf-8"));
101	
102	const unknownType = findUnknownItemType(scenario);
103	if (unknownType !== undefined) {
104	  process.stderr.write(`error: unknown item type "${unknownType}"\n`);
105	  process.exit(1);
106	}
107	
108	process.stdout.write(JSON.stringify({ results: runScenario(scenario) }));
109

